INSERT INTO ai_knowledge_base (admin_id, question_pattern, answer_content) VALUES
                                                                               (1, 'Xin chào', 'Dạ, xin chào quý khách! Chào mừng quý khách đến với Khách sạn của chúng tôi. Tôi là trợ lý ảo AI, tôi có thể giúp gì cho kỳ nghỉ sắp tới của quý khách ạ?'),
                                                                               (1, 'Bạn là ai?', 'Dạ, tôi là trợ lý ảo AI tự động của khách sạn, hoạt động 24/7 để hỗ trợ quý khách giải đáp mọi thắc mắc và hướng dẫn đặt phòng ạ.'),
                                                                               (1, 'Chào buổi sáng', 'Dạ chào quý khách! Chúc quý khách một ngày thật nhiều niềm vui. Quý khách cần hỗ trợ thông tin gì về dịch vụ khách sạn hay đặt phòng không ạ?'),
                                                                               (1, 'Cảm ơn', 'Dạ, không có gì ạ! Rất hân hạnh được phục vụ quý khách. Nếu cần thêm hỗ trợ, quý khách cứ nhắn tin cho tôi nhé.'),
                                                                               (1, 'Tạm biệt', 'Dạ tạm biệt quý khách. Chúc quý khách một ngày tốt lành và hy vọng sớm được đón tiếp quý khách tại khách sạn!'),
                                                                               (1, 'Khách sạn ở đâu?', 'Dạ, khách sạn chúng tôi tọa lạc tại trung tâm thành phố Đà Nẵng. Vị trí rất đắc địa, thuận tiện di chuyển đến các điểm tham quan nổi tiếng ạ.'),
                                                                               (1, 'Từ sân bay đến khách sạn đi thế nào?', 'Dạ, khách sạn cách Sân bay Quốc tế Đà Nẵng chỉ khoảng 15 phút di chuyển. Quý khách có thể đi taxi, Grab, hoặc đặt trước dịch vụ xe đưa đón sân bay của khách sạn ạ.'),
                                                                               (1, 'Khách sạn có gần biển không?', 'Dạ, khách sạn nằm rất gần biển ạ. Quý khách chỉ mất khoảng 3-5 phút đi bộ là có thể tận hưởng không khí biển mát lành.'),
                                                                               (1, 'Hotline lễ tân số mấy?', 'Dạ, hotline hỗ trợ 24/7 của Lễ tân khách sạn là 0236.XXX.XXXX. Quý khách có thể gọi bất cứ lúc nào để được hỗ trợ trực tiếp ạ.'),
                                                                               (1, 'Khách sạn mấy sao?', 'Dạ, chúng tôi tự hào là khách sạn đạt tiêu chuẩn dịch vụ cao cấp, mang lại trải nghiệm lưu trú sang trọng, tiện nghi và đẳng cấp nhất cho khách hàng.'),
                                                                               (1, 'Cách đặt phòng trên web?', 'Dạ, để đặt phòng: B1: Nhập ngày Check-in/Check-out. B2: Hệ thống hiện danh sách phòng trống. B3: Chọn phòng ưng ý và tiến hành thanh toán cọc ạ.'),
                                                                               (1, 'Có các hình thức thanh toán nào?', 'Dạ, khách sạn hỗ trợ 3 phương thức thanh toán: 1. Chuyển khoản ngân hàng, 2. Ví điện tử MoMo, 3. Tiền mặt tại quầy ạ.'),
                                                                               (1, 'Đặt phòng có cần cọc không?', 'Dạ có ạ. Để hệ thống giữ phòng và xác nhận đặt chỗ thành công, quý khách bắt buộc phải thanh toán đặt cọc trước ạ.'),
                                                                               (1, 'Cọc bao nhiêu phần trăm?', 'Dạ, theo quy định, quý khách cần thanh toán cọc tối thiểu 20% tổng giá trị đơn đặt phòng để hệ thống xác nhận giữ phòng ạ.'),
                                                                               (1, 'Thanh toán bằng MoMo được không?', 'Dạ hoàn toàn được ạ. MoMo là một trong 3 phương thức thanh toán chính thức của khách sạn. Hệ thống sẽ tạo mã QR để quý khách quét cực kỳ nhanh chóng.'),
                                                                               (1, 'Chuyển khoản ngân hàng có được không?', 'Dạ được ạ. Quý khách có thể chọn phương thức Chuyển khoản ngân hàng. Hệ thống sẽ hiển thị mã QR và thông tin tài khoản để quý khách chuyển cọc 20% ạ.'),
                                                                               (1, 'Đến nơi trả tiền mặt 100% được không?', 'Dạ rất tiếc, để giữ phòng trên hệ thống, quý khách bắt buộc phải cọc trước 20% qua Ngân hàng hoặc MoMo. 80% còn lại quý khách có thể thanh toán bằng tiền mặt khi nhận phòng ạ.'),
                                                                               (1, 'Xem phòng trống ở đâu?', 'Dạ, quý khách chỉ cần chọn Ngày nhận phòng và Ngày trả phòng trên trang chủ, bấm Tìm kiếm, hệ thống sẽ tự động lọc ra các loại phòng còn trống ạ.'),
                                                                               (1, 'Giá trên web là 1 đêm hay nhiều đêm?', 'Dạ, giá phòng hiển thị trên danh sách ban đầu là giá cho 1 đêm. Khi quý khách chọn đủ ngày, hệ thống sẽ tự động tính tổng tiền cho toàn bộ kỳ nghỉ ạ.'),
                                                                               (1, 'Hủy phòng có được hoàn cọc không?', 'Dạ, nếu quý khách hủy phòng trước 3 ngày so với ngày Check-in, khách sạn sẽ hoàn lại 100% tiền cọc. Nếu hủy sát ngày, số tiền cọc 20% sẽ không được hoàn lại ạ.'),
                                                                               (1, 'Có các loại phòng nào?', 'Dạ, khách sạn có 6 hạng phòng: Standard, Superior, Deluxe, VIP, Suite, và Family. Quý khách đi mấy người để tôi tư vấn loại phòng phù hợp ạ?'),
                                                                               (1, 'Phòng Standard có gì?', 'Dạ, Standard là hạng phòng tiêu chuẩn, giá tiết kiệm nhất. Trang bị đầy đủ giường nệm êm ái, Smart TV, điều hòa, và phòng tắm riêng biệt ạ.'),
                                                                               (1, 'Phòng Superior có view không?', 'Dạ, phòng Superior rộng rãi hơn Standard và thường có cửa sổ lớn với hướng nhìn thoáng đãng ra thành phố, kèm theo khu vực bàn ghế thư giãn ạ.'),
                                                                               (1, 'Phòng Deluxe có ban công không?', 'Dạ có ạ, phần lớn phòng hạng Deluxe đều sở hữu ban công riêng cực chill, nội thất sang trọng và bồn tắm nằm thư giãn trong phòng tắm ạ.'),
                                                                               (1, 'Phòng VIP có gì đặc biệt?', 'Dạ, phòng VIP nằm ở các tầng cao với view tuyệt đẹp. Đồ trang trí nội thất xịn sò, hệ thống đèn thông minh và quý khách được đặc quyền nhận/trả phòng ưu tiên ạ.'),
                                                                               (1, 'Phòng Suite là gì?', 'Dạ, Suite là hạng phòng đẳng cấp nhất (Hoàng gia). Không gian siêu rộng tách biệt phòng ngủ và phòng khách, nội thất xa xỉ và có quản gia riêng 24/7 ạ.'),
                                                                               (1, 'Gia đình 4 người nên ở phòng nào?', 'Dạ, với gia đình 2 người lớn và 2 trẻ em, quý khách nên chọn hạng phòng Family là thoải mái và phù hợp nhất ạ.'),
                                                                               (1, 'Phòng Family có bếp không?', 'Dạ có, phòng Family được thiết kế đặc biệt có 1 khu bếp nhỏ tiện lợi để hâm nóng đồ ăn cho em bé, kèm theo bàn ăn gia đình ạ.'),
                                                                               (1, 'Trong phòng tắm có máy sấy tóc không?', 'Dạ có ạ. Toàn bộ các phòng đều được trang bị máy sấy tóc, khăn tắm, áo choàng và các đồ dùng vệ sinh cá nhân miễn phí ạ.'),
                                                                               (1, 'Smart TV trong phòng có Youtube không?', 'Dạ, tất cả TV trong phòng đều là Smart TV kết nối mạng internet tốc độ cao, quý khách có thể thoải mái xem Youtube, Netflix ạ.'),
                                                                               (1, 'Trong phòng có két sắt không?', 'Dạ có, khách sạn trang bị tủ quần áo rộng rãi và két sắt điện tử bảo mật trong tất cả các phòng để quý khách cất giữ tài sản giá trị ạ.'),
                                                                               (1, 'Giường phòng Standard là giường gì?', 'Dạ, phòng Standard có 2 lựa chọn: 1 giường đôi lớn (Double Bed) hoặc 2 giường đơn (Twin Bed) tùy vào nhu cầu của quý khách ạ.'),
                                                                               (1, 'Tôi muốn kê thêm giường phụ (Extra bed) được không?', 'Dạ được ạ. Khách sạn có dịch vụ kê thêm giường phụ đối với các hạng phòng từ Superior trở lên do cần không gian đủ rộng ạ.'),
                                                                               (1, 'Giá giường phụ là bao nhiêu?', 'Dạ, phí kê thêm giường phụ (Extra bed) là 500,000 VNĐ/đêm, mức giá này đã bao gồm luôn suất ăn sáng buffet cho 1 người rồi ạ.'),
                                                                               (1, 'Xin nôi em bé có mất tiền không?', 'Dạ không ạ, khách sạn cung cấp nôi/cũi trẻ em hoàn toàn miễn phí. Quý khách vui lòng ghi chú khi đặt phòng để nhân viên setup sẵn ạ.'),
                                                                               (1, 'Check in và check out mấy giờ?', 'Dạ, giờ nhận phòng (Check-in) quy định là từ 14:00 chiều, và giờ trả phòng (Check-out) là trước 12:00 trưa ngày hôm sau ạ.'),
                                                                               (1, 'Nhận phòng sớm (early check in) được không?', 'Dạ, việc nhận phòng sớm phụ thuộc vào tình trạng phòng trống thực tế lúc quý khách đến. Nếu có phòng, khách sạn sẽ hỗ trợ, có thể kèm theo phụ phí nếu nhận quá sớm ạ.'),
                                                                               (1, 'Trả phòng trễ (late check out) tính phí sao?', 'Dạ, nếu trả phòng trễ trước 18:00 sẽ phụ thu 50% tiền phòng 1 đêm. Sau 18:00 sẽ tính 100% tiền phòng ạ (Tùy thuộc vào việc còn phòng trống hay không).'),
                                                                               (1, 'Trẻ em có bị tính thêm phí không?', 'Dạ, trẻ dưới 6 tuổi được miễn phí ngủ chung giường bố mẹ. Trẻ 6-11 tuổi phụ thu ăn sáng. Trẻ từ 12 tuổi tính như người lớn và cần kê giường phụ ạ.'),
                                                                               (1, 'Có cho mang chó mèo vào không?', 'Dạ rất tiếc, để đảm bảo tiêu chuẩn vệ sinh và không gian chung, khách sạn hiện không cho phép khách hàng mang theo thú cưng vào khuôn viên ạ.'),
                                                                               (1, 'Khách sạn có hồ bơi không?', 'Dạ có ạ, khách sạn sở hữu một hồ bơi vô cực tuyệt đẹp nằm trên tầng thượng (Rooftop) dành riêng cho khách lưu trú ạ.'),
                                                                               (1, 'Hồ bơi mở cửa đến mấy giờ?', 'Dạ, hồ bơi phục vụ miễn phí mỗi ngày từ 6:00 sáng đến 21:00 tối ạ.'),
                                                                               (1, 'Khách sạn có chỗ để ô tô không?', 'Dạ có, khách sạn có tầng hầm đỗ xe rộng rãi và an ninh 24/7. Khách lưu trú sẽ được đỗ xe máy và ô tô hoàn toàn miễn phí ạ.'),
                                                                               (1, 'Có dịch vụ xe đưa đón sân bay không?', 'Dạ có ạ, khách sạn cung cấp dịch vụ đưa đón sân bay có thu phí. Quý khách vui lòng báo trước lịch trình với Lễ tân để chúng tôi sắp xếp xe ạ.'),
                                                                               (1, 'Buffet sáng ăn từ mấy giờ?', 'Dạ, bữa sáng buffet tiêu chuẩn quốc tế được phục vụ tại nhà hàng tầng 3 từ 6:30 sáng đến 9:30 sáng mỗi ngày ạ.'),
                                                                               (1, 'Tôi muốn đánh giá phòng thì làm thế nào?', 'Dạ, để đảm bảo tính khách quan và trải nghiệm thực tế, quý khách cần hoàn tất thủ tục trả phòng (Check-out) tại quầy lễ tân. Sau đó, hệ thống mới mở chức năng đánh giá chuyến đi cho quý khách ạ.'),
                                                                               (1, 'Đang ở chưa check-out có review được không?', 'Dạ không được ạ. Hệ thống khách sạn chỉ cho phép khách hàng gửi đánh giá và chấm điểm phòng sau khi đã hoàn tất thủ tục Check-out thành công ạ.'),
                                                                               (1, 'Tôi mới đặt phòng xong có đánh giá được luôn không?', 'Dạ chưa được ạ. Chức năng đánh giá (Review) chỉ được mở khóa sau khi quý khách đã thực sự đến lưu trú và hoàn thành việc Check-out trả phòng ạ.'),
                                                                               (1, 'Đánh giá khách sạn có được tích điểm không?', 'Dạ có ạ. Ngay sau khi check-out và để lại đánh giá về phòng trên hệ thống, quý khách sẽ nhận được điểm thưởng hoặc voucher giảm giá cho lần đặt phòng tiếp theo ạ.'),
                                                                               (1, 'Tại sao tôi không thấy nút đánh giá phòng?', 'Dạ, nút đánh giá sẽ tự động hiển thị trong phần lịch sử đặt phòng của quý khách SAU KHI quý khách đã hoàn tất việc Check-out tại khách sạn ạ.');
INSERT INTO ai_knowledge_base (admin_id, question_pattern, answer_content) VALUES
                                                                               (1, 'Tôi muốn trang trí phòng trăng mật (Honeymoon) có được không?', 'Dạ hoàn toàn tuyệt vời ạ! Khách sạn có gói trang trí Honeymoon vô cùng lãng mạn với hoa hồng xếp hình tim, bóng bay và thiên nga gấp khăn. Quý khách vui lòng báo trước 1 ngày để chúng tôi chuẩn bị nhé.'),
                                                                               (1, 'Hôm nay sinh nhật tôi, khách sạn có tặng bánh không?', 'Dạ, khách sạn luôn có một món quà bất ngờ (bánh kem nhỏ hoặc trái cây) dành tặng những vị khách lưu trú ngay dịp sinh nhật. Quý khách hãy báo với Lễ tân để chúng tôi chuẩn bị ạ!'),
                                                                               (1, 'Có dịch vụ dọn phòng buổi tối không?', 'Dạ có ạ. Khách sạn cung cấp dịch vụ dọn phòng và chỉnh trang giường ngủ buổi tối (Turndown Service) để đảm bảo quý khách có một giấc ngủ thư thái nhất.'),
                                                                               (1, 'Tôi muốn chọn phòng ở tầng cao được không?', 'Dạ, khách sạn luôn cố gắng sắp xếp phòng ở tầng cao theo yêu cầu của quý khách nếu tình trạng phòng trống tại thời điểm Check-in cho phép ạ. Quý khách cứ ghi chú lại khi đặt phòng nhé.'),
                                                                               (1, 'Gia đình tôi đi đông, muốn thuê 2 phòng có cửa thông nhau không?', 'Dạ có ạ. Khách sạn có hạng phòng Connecting Room (2 phòng thông nhau qua 1 cửa phụ bên trong), cực kỳ phù hợp cho gia đình cần sự gắn kết nhưng vẫn đảm bảo riêng tư.'),
                                                                               (1, 'Thẻ phòng của tôi không mở được cửa', 'Dạ, thành thật xin lỗi quý khách. Có thể thẻ đã bị từ tính làm nhiễu hoặc hết hạn giờ. Quý khách vui lòng mang thẻ xuống quầy Lễ tân để chúng tôi kích hoạt lại trong 1 nốt nhạc ạ.'),
                                                                               (1, 'Phòng ồn ào quá tôi không ngủ được', 'Dạ, khách sạn vô cùng xin lỗi về trải nghiệm này. Quý khách vui lòng gọi ngay Lễ tân (phím 0), chúng tôi sẽ cử bảo vệ lên kiểm tra hoặc hỗ trợ đổi phòng khác yên tĩnh hơn cho quý khách ngay lập tức ạ.'),
                                                                               (1, 'Tôi lỡ quên đồ trong phòng sau khi check-out', 'Dạ quý khách đừng quá lo lắng. Xin hãy cung cấp số phòng và loại đồ vật bị quên. Bộ phận Buồng phòng sẽ kiểm tra, lưu kho cẩn thận và liên hệ để gửi trả lại cho quý khách ạ.'),
                                                                               (1, 'Bồn cầu trong phòng bị tắc/chảy nước', 'Dạ xin lỗi quý khách về sự cố này. Quý khách vui lòng gọi số 0, bộ phận Kỹ thuật sẽ có mặt tại phòng trong vòng 5 phút để khắc phục ngay lập tức ạ.'),
                                                                               (1, 'Tôi muốn hủy phòng sát giờ (trong vòng 24h) có được hoàn cọc không?', 'Dạ rất tiếc, theo chính sách đặt phòng, nếu hủy sát ngày (trong vòng 3 ngày trước Check-in), khoản cọc 20% sẽ không được hoàn lại để bù đắp chi phí giữ phòng của hệ thống ạ.'),
                                                                               (1, 'Tôi đang ở nhưng có việc đột xuất muốn trả phòng sớm có được hoàn tiền không?', 'Dạ, trong trường hợp quý khách trả phòng sớm hơn so với ngày dự kiến (Early Departure), khách sạn sẽ tính phí 100% cho đêm lưu trú tiếp theo. Các đêm còn lại (nếu có) sẽ được hoàn trả ạ.'),
                                                                               (1, 'Tôi muốn gia hạn ở thêm 1 đêm nữa thì làm sao?', 'Dạ, nếu quý khách muốn ở thêm (Extend stay), vui lòng liên hệ Lễ tân càng sớm càng tốt để chúng tôi kiểm tra tình trạng phòng và giữ phòng cho quý khách với mức giá ưu đãi ạ.'),
                                                                               (1, 'Người khác chuyển khoản cọc giùm tôi được không?', 'Dạ hoàn toàn được ạ. Quý khách chỉ cần ghi chú đúng Mã Đặt Phòng (Booking ID) vào nội dung chuyển khoản để hệ thống tự động nhận diện và cập nhật trạng thái đặt cọc thành công.'),
                                                                               (1, 'Khách sạn có xuất hóa đơn đỏ (VAT) không?', 'Dạ có ạ. Khách sạn luôn xuất hóa đơn điện tử VAT cho khách lưu trú. Quý khách vui lòng cung cấp thông tin công ty và mã số thuế lúc check-out để nhân viên tiến hành xuất hóa đơn ạ.'),
                                                                               (1, 'Dịch vụ Spa có những gì?', 'Dạ, khu vực Spa tại tầng 4 cung cấp đa dạng các liệu trình chăm sóc sức khỏe và sắc đẹp như: Massage body đá nóng, xông hơi, chăm sóc da mặt và ngâm chân thảo dược ạ.'),
                                                                               (1, 'Đi Spa có cần đặt lịch trước không?', 'Dạ, để đảm bảo phục vụ chu đáo nhất và không phải chờ đợi, quý khách nên gọi điện đặt lịch trước với bộ phận Spa từ 1-2 tiếng ạ.'),
                                                                               (1, 'Khách bên ngoài không đặt phòng có được bơi không?', 'Dạ rất tiếc, để đảm bảo không gian riêng tư và thoải mái nhất cho khách lưu trú, hồ bơi của khách sạn hiện tại chỉ phục vụ khách có đặt phòng thôi ạ.'),
                                                                               (1, 'Phòng Gym có mở cửa 24/24 không?', 'Dạ, phòng Gym của khách sạn mở cửa phục vụ từ 5:30 sáng đến 22:00 đêm mỗi ngày, với đầy đủ các thiết bị tập luyện hiện đại ạ.'),
                                                                               (1, 'Nhà hàng có phục vụ đồ ăn chay không?', 'Dạ có ạ. Nhà hàng khách sạn luôn chuẩn bị sẵn góc ẩm thực chay trong tiệc buffet sáng, đồng thời phục vụ các món chay gọi món (A La Carte) cực kỳ tinh tế và ngon miệng.'),
                                                                               (1, 'Có được hút thuốc trong phòng không?', 'Dạ không ạ. Toàn bộ phòng ngủ và không gian kín bên trong khách sạn là khu vực cấm hút thuốc. Khách sạn sẽ phạt phí làm sạch 2.000.000 VNĐ nếu phát hiện hút thuốc trong phòng ạ.'),
                                                                               (1, 'Vậy tôi có thể hút thuốc ở đâu?', 'Dạ, quý khách có thể hút thuốc tại khu vực Ban công của các phòng Deluxe, hoặc tại khu vực cho phép hút thuốc được bố trí sẵn ở khu vườn tầng trệt và khu vực sảnh ngoài trời ạ.'),
                                                                               (1, 'Khách sạn có quầy Bar không?', 'Dạ có ạ. Sky Bar nằm cạnh hồ bơi trên tầng thượng là một điểm đến tuyệt vời. Phục vụ đa dạng cocktail, rượu vang và có nhạc acoustic nhẹ nhàng vào cuối tuần ạ.'),
                                                                               (1, 'Giặt ủi có lấy ngay trong ngày được không?', 'Dạ có ạ. Nếu quý khách gửi đồ giặt trước 10:00 sáng, khách sạn sẽ hoàn trả quần áo sạch sẽ, là ủi phẳng phiu vào trước 18:00 chiều cùng ngày. Trong tủ đồ (STORAGE) có sẵn túi giặt để quý khách sử dụng ạ.'),
                                                                               (1, 'Khách sạn có dịch vụ trông trẻ không?', 'Dạ có ạ. Khách sạn cung cấp dịch vụ Babysitting chuyên nghiệp (có tính phí). Quý khách vui lòng đặt trước 24 tiếng để chúng tôi sắp xếp bảo mẫu tốt nhất cho bé ạ.'),
                                                                               (1, 'Tôi có thể mượn bàn ủi (bàn là) không?', 'Dạ, nếu quý khách không muốn dùng dịch vụ giặt ủi, quý khách có thể gọi Lễ tân mượn bàn ủi và cầu là. Chúng tôi sẽ mang lên tận phòng (ELECTRONIC) hoàn toàn miễn phí ạ.'),
                                                                               (1, 'Lễ tân có đổi ngoại tệ (USD, EUR) không?', 'Dạ có, quầy Lễ tân hỗ trợ dịch vụ thu đổi ngoại tệ (Exchange) theo tỷ giá quy định của ngân hàng hiện hành để tạo sự thuận tiện tối đa cho quý khách nước ngoài.'),
                                                                               (1, 'Xung quanh khách sạn có siêu thị tiện lợi không?', 'Dạ có ạ. Ngay bên cạnh khách sạn (khoảng 50m) có các cửa hàng tiện lợi như Vinmart, Circle K mở cửa 24/7 vô cùng tiện lợi.'),
                                                                               (1, 'Gần khách sạn có quán hải sản nào ngon?', 'Dạ, dọc con đường phía trước khách sạn có rất nhiều nhà hàng hải sản tươi sống nổi tiếng. Quý khách có thể gặp các bạn Concierge/Lễ tân để nhận bản đồ và gợi ý chi tiết nhé.'),
                                                                               (1, 'Từ khách sạn ra phố cổ Hội An bao xa?', 'Dạ, từ khách sạn di chuyển vào phố cổ Hội An mất khoảng 40 - 45 phút chạy xe. Khách sạn có xe đưa đón đi Hội An hàng ngày, quý khách có thể đăng ký tại quầy Lễ tân ạ.'),
                                                                               (1, 'Khách sạn có cho thuê xe máy không?', 'Dạ có ạ, khách sạn có liên kết với đối tác cung cấp xe máy cho thuê chất lượng cao (Xe số, xe ga). Giá thuê từ 120.000 - 150.000 VNĐ/ngày, giao nhận xe trực tiếp tại sảnh ạ.'),
                                                                               (1, 'Đồ uống trong Tủ lạnh (Minibar) có tính tiền không?', 'Dạ, các loại nước ngọt, bia, bánh snack trong Minibar (tủ lạnh nhỏ) sẽ bị tính phí theo bảng giá để trên bàn. Còn 2 chai nước suối tinh khiết để trên bàn là hoàn toàn miễn phí mỗi ngày ạ.'),
                                                                               (1, 'Nước suối có miễn phí không?', 'Dạ, mỗi ngày khách sạn cung cấp miễn phí 2 chai nước suối, kèm theo trà và cà phê dạng gói đặt tại khu vực bình đun siêu tốc trong phòng ạ.'),
                                                                               (1, 'Phòng có lò vi sóng không?', 'Dạ, lò vi sóng (KITCHEN) chỉ được trang bị tại hạng phòng Family và phòng Suite. Nếu quý khách ở phòng khác mà cần hâm nóng đồ ăn, vui lòng nhờ các bạn Lễ tân hoặc nhà hàng hỗ trợ ạ.'),
                                                                               (1, 'Bồn tắm trong phòng có sục (Jacuzzi) không?', 'Dạ, bồn tắm sục massage (Jacuzzi) cao cấp thuộc nhóm tiện nghi phòng tắm (BATHROOM) chỉ được trang bị riêng cho hạng phòng VIP và Suite để mang lại trải nghiệm thư giãn tối đa ạ.'),
                                                                               (1, 'Tôi muốn xin thêm gối ngủ có được không?', 'Dạ hoàn toàn được ạ. Nếu quý khách cần thêm gối ngủ (BED) để nằm thoải mái hơn, hãy gọi Lễ tân, chúng tôi sẽ mang gối lên phòng miễn phí ngay lập tức.'),
                                                                               (1, 'Phòng có cửa sổ mở ra được không?', 'Dạ, vì lý do an toàn cháy nổ và bảo đảm hiệu suất điều hòa, một số cửa sổ kính lớn không thể mở hết cỡ. Tuy nhiên các hạng phòng có ban công thì cửa trượt mở ra hoàn toàn để đón gió trời ạ.'),
                                                                               (1, 'Dép đi trong phòng (Slipper) có được mang về không?', 'Dạ, dép vải đi trong phòng là vật phẩm miễn phí dành cho khách sử dụng trong thời gian lưu trú. Nếu quý khách thích, hoàn toàn có thể mang về làm kỷ niệm ạ.'),
                                                                               (1, 'Dầu gội, sữa tắm trong phòng là loại gì?', 'Dạ, các sản phẩm Amenities (Dầu gội, sữa tắm) trong phòng tắm (BATHROOM) của khách sạn được chiết xuất từ tinh dầu thiên nhiên cao cấp, rất an toàn và thư giãn cho làn da ạ.'),
                                                                               (1, 'Tôi có thể dẫn bạn bè đến phòng chơi được không?', 'Dạ được ạ. Tuy nhiên, vì lý do an ninh, khách thăm viếng chỉ được phép lưu lại trong phòng đến 22:00 đêm. Sau giờ này, khách cần làm thủ tục lưu trú theo quy định pháp luật ạ.'),
                                                                               (1, 'Khách ngoài đến thăm có phải để lại giấy tờ không?', 'Dạ có ạ. Để đảm bảo an ninh tuyệt đối cho toàn bộ khách hàng, tất cả khách không lưu trú khi lên phòng thăm người thân đều phải xuất trình và để lại CMND/CCCD tại quầy Bảo vệ/Lễ tân ạ.'),
                                                                               (1, 'Khách sạn có camera an ninh không?', 'Dạ, khách sạn trang bị hệ thống camera an ninh 24/7 bao quát tất cả các khu vực công cộng, hành lang và hầm xe để đảm bảo an toàn tối đa cho quý khách.'),
                                                                               (1, 'Khóa cửa phòng dùng bằng gì?', 'Dạ, toàn bộ hệ thống cửa phòng đều sử dụng khóa thẻ từ thông minh cực kỳ an toàn, chỉ cấp quyền truy cập đúng phòng và đúng tầng của quý khách thôi ạ.'),
                                                                               (1, 'Tôi có thể sửa lại review/đánh giá sau khi viết không?', 'Dạ rất tiếc, để đảm bảo tính minh bạch của hệ thống, một khi đánh giá đã được gửi đi sau khi Check-out, quý khách không thể chỉnh sửa lại nội dung được nữa ạ.'),
                                                                               (1, 'Tôi đánh giá 1 sao thì có bị khách sạn ẩn đi không?', 'Dạ tuyệt đối không ạ. Khách sạn trân trọng mọi phản hồi. Những đánh giá dù là 1 sao sẽ được giữ nguyên hiển thị để Ban Giám Đốc lấy đó làm động lực khắc phục và cải thiện chất lượng dịch vụ.'),
                                                                               (1, 'Nếu tôi quên đánh giá phòng thì bao lâu sẽ bị khóa?', 'Dạ, tính năng gửi đánh giá sẽ được mở trong vòng 14 ngày kể từ ngày quý khách hoàn tất Check-out. Sau 14 ngày, chức năng này sẽ tự động đóng lại ạ.'),
                                                                               (1, 'Quét mã MoMo để thanh toán cọc bị lỗi thì sao?', 'Dạ, nếu mã QR MoMo báo lỗi, quý khách có thể tải lại trang (F5) để lấy mã mới, hoặc chuyển sang hình thức Chuyển khoản ngân hàng. Nếu vẫn lỗi, quý khách vui lòng nhắn Lễ tân hỗ trợ tạo booking tay ạ.'),
                                                                               (1, 'Tôi chuyển khoản cọc nhưng ghi sai mã booking thì làm sao?', 'Dạ, quý khách đừng lo. Nếu lỡ ghi sai nội dung chuyển khoản, quý khách vui lòng nhắn tin cho Lễ tân, chụp kèm biên lai giao dịch. Kế toán sẽ đối soát và xác nhận thủ công cho quý khách ngay ạ.'),
                                                                               (1, 'Tôi có thể quẹt thẻ tín dụng (Visa/Mastercard) khi trả tiền mặt tại quầy không?', 'Dạ hoàn toàn được ạ. Quầy Lễ tân có trang bị máy POS, hỗ trợ quẹt các loại thẻ tín dụng, thẻ ghi nợ nội địa và quốc tế hoàn toàn miễn phí quẹt thẻ ạ.');
INSERT INTO ai_knowledge_base (admin_id, question_pattern, answer_content) VALUES
                                                                               (1, 'Tôi có thể thanh toán một nửa bằng tiền mặt, một nửa bằng thẻ được không?', 'Dạ hoàn toàn được ạ. Quý khách có thể kết hợp nhiều phương thức thanh toán tại quầy Lễ tân lúc nhận/trả phòng để thuận tiện nhất cho mình ạ.'),
                                                                               (1, 'Tôi đặt phòng cho người thân (bố mẹ) được không?', 'Dạ được ạ. Khi đặt phòng, quý khách chỉ cần nhập thông tin tên và số điện thoại của người sẽ nhận phòng. Quý khách có thể thanh toán cọc hoặc thanh toán 100% trước để bố mẹ đến chỉ việc nghỉ ngơi thôi ạ.'),
                                                                               (1, 'Tôi muốn xuất hóa đơn VAT cho khoản tiền cọc 20% trước được không?', 'Dạ, theo quy định của cơ quan thuế, khách sạn sẽ xuất hóa đơn VAT gộp 1 lần cho tổng giá trị kỳ nghỉ vào ngày quý khách làm thủ tục Check-out trả phòng ạ.'),
                                                                               (1, 'Nhận phòng lúc nửa đêm (2-3h sáng) có ai trực không?', 'Dạ có ạ. Quầy Lễ tân và bộ phận An ninh của khách sạn hoạt động 24/7. Dù quý khách đến lúc nửa đêm, nhân viên vẫn luôn sẵn sàng chào đón và làm thủ tục Check-in ạ.'),
                                                                               (1, 'Khi nhận phòng có phải đặt cọc thêm tiền hư hỏng đồ (Incidental deposit) không?', 'Dạ có ạ. Để đảm bảo cho các dịch vụ phát sinh (minibar, giặt ủi...), khách sạn sẽ tạm giữ một khoản cọc nhỏ (bằng thẻ hoặc tiền mặt) lúc Check-in và sẽ hoàn trả đầy đủ lúc Check-out nếu không phát sinh chi phí ạ.'),
                                                                               (1, 'Tiền hoàn hủy phòng sẽ được trả lại trong bao lâu?', 'Dạ, nếu quý khách hủy phòng hợp lệ, tiền cọc sẽ được kế toán hoàn lại vào tài khoản ngân hàng hoặc MoMo của quý khách trong vòng 3-5 ngày làm việc ạ.'),
                                                                               (1, 'Nệm (giường) trong phòng là loại cứng hay mềm?', 'Dạ, toàn bộ giường (BED) của khách sạn sử dụng nệm lò xo túi độc lập cao cấp tiêu chuẩn 5 sao, độ đàn hồi vừa phải, vô cùng êm ái và không gây đau lưng ạ.'),
                                                                               (1, 'Tôi có thể xin thêm chăn (mền) không?', 'Dạ có ạ. Nếu quý khách cảm thấy lạnh và cần thêm chăn (BED), vui lòng gọi bộ phận Buồng phòng. Chúng tôi sẽ mang chăn sạch lên phòng quý khách miễn phí ạ.'),
                                                                               (1, 'Phòng tắm có trang bị vòi xịt vệ sinh (Bidet) không?', 'Dạ có ạ. Tất cả hệ thống phòng tắm (BATHROOM) của khách sạn đều được trang bị bồn cầu cao cấp kèm theo vòi xịt vệ sinh tiện dụng và hiện đại ạ.'),
                                                                               (1, 'Trong phòng có dao cạo râu và kem đánh răng không?', 'Dạ có ạ. Bộ đồ dùng cá nhân (Amenities) trong phòng tắm (BATHROOM) đã bao gồm sẵn bàn chải, kem đánh răng, dao cạo râu, lược và tăm bông. Quý khách không cần mang theo đâu ạ.'),
                                                                               (1, 'Phòng Standard có bàn làm việc không?', 'Dạ, dù là hạng phòng tiêu chuẩn, phòng Standard vẫn được bố trí một khu vực bàn và ghế (TABLE, CHAIR) nhỏ gọn, đủ ánh sáng (LIGHTING) để quý khách có thể ngồi làm việc với laptop ạ.'),
                                                                               (1, 'Tôi muốn xin thêm móc treo quần áo', 'Dạ, trong tủ quần áo (STORAGE) đã có sẵn móc treo gỗ. Nếu quý khách cần thêm để treo đồ, xin hãy gọi Lễ tân, chúng tôi sẽ mang thêm lên ngay lập tức ạ.'),
                                                                               (1, 'Trong khu vực bếp của phòng Family có xoong nồi không?', 'Dạ có ạ. Bếp (KITCHEN) của hạng phòng Family được trang bị sẵn bếp từ an toàn, xoong nồi cơ bản, chén bát và thìa dĩa để gia đình có thể nấu những bữa ăn nhẹ cho em bé ạ.'),
                                                                               (1, 'Điều hòa trong phòng có tự chỉnh nhiệt độ được không?', 'Dạ có ạ. Hệ thống điều hòa (ELECTRONIC) là loại điều khiển độc lập cho từng phòng. Quý khách có thể thoải mái tăng giảm nhiệt độ và tốc độ gió theo ý thích bằng bảng điều khiển trên tường.'),
                                                                               (1, 'Khách sạn có dịch vụ gọi đồ ăn lên phòng (Room Service) không?', 'Dạ có ạ. Khách sạn cung cấp dịch vụ In-room Dining phục vụ 24/7. Quý khách chỉ cần xem menu đặt trên bàn (TABLE) và gọi phím số 3, đồ ăn sẽ được mang lên tận phòng ạ.'),
                                                                               (1, 'Nhà hàng có thực đơn dành riêng cho trẻ em (Kids menu) không?', 'Dạ có ạ. Nhà hàng luôn chuẩn bị sẵn các món ăn phù hợp với khẩu vị và dinh dưỡng của trẻ nhỏ như: cháo dinh dưỡng, súp, mì ý, và khoai tây chiên ạ.'),
                                                                               (1, 'Tôi bị dị ứng đậu phộng, nhà hàng có hỗ trợ nấu riêng không?', 'Dạ chắc chắn rồi ạ. Quý khách vui lòng báo tình trạng dị ứng thực phẩm hoặc chế độ ăn kiêng (Gluten-free, Halal) cho nhân viên nhà hàng để Bếp trưởng chuẩn bị phần ăn an toàn tuyệt đối cho quý khách.'),
                                                                               (1, 'Tôi trả phòng lúc 5h sáng để ra sân bay, có được ăn sáng không?', 'Dạ, nếu quý khách phải khởi hành sớm trước giờ buffet sáng mở cửa (6:30), khách sạn sẽ hỗ trợ chuẩn bị hộp thức ăn sáng mang đi (Take-away Breakfast). Quý khách vui lòng báo lễ tân trước 21:00 tối hôm trước ạ.'),
                                                                               (1, 'Khách sạn có Welcome Drink (nước uống chào mừng) không?', 'Dạ có ạ. Trong lúc chờ nhân viên làm thủ tục Check-in, quý khách sẽ được mời thưởng thức Welcome Drink là nước trái cây nhiệt đới mát lạnh và khăn lạnh tại sảnh chờ ạ.'),
                                                                               (1, 'Khách sạn có hỗ trợ in ấn tài liệu không?', 'Dạ có ạ. Khách sạn có khu vực Business Center với máy tính và máy in (ELECTRONIC). Nếu quý khách chỉ in vài tờ tài liệu cơ bản, Lễ tân sẽ hỗ trợ in hoàn toàn miễn phí ạ.'),
                                                                               (1, 'Tôi lỡ mang theo sạc điện thoại khác đầu cắm, khách sạn có ổ chuyển đổi không?', 'Dạ có ạ. Khách sạn có mượn ổ cắm chuyển đổi đa năng (Adapter). Quý khách vui lòng liên hệ Lễ tân để mượn và gửi lại khi làm thủ tục Check-out ạ.'),
                                                                               (1, 'Trời mưa tôi có thể mượn ô (dù) của khách sạn không?', 'Dạ có ạ. Tại quầy Lễ tân và cửa chính luôn có sẵn ô (dù) bản to để quý khách mượn miễn phí khi ra ngoài ạ.'),
                                                                               (1, 'Khách sạn có xe lăn cho người cao tuổi/người khuyết tật không?', 'Dạ có ạ. Khách sạn luôn có sẵn xe lăn tiêu chuẩn tại sảnh và hệ thống đường dốc (ramp), thang máy rộng rãi để hỗ trợ tối đa cho người cao tuổi và kháchếm khuyết ạ.'),
                                                                               (1, 'Khu vực hồ bơi có cung cấp khăn tắm không hay phải mang từ phòng xuống?', 'Dạ, quý khách không cần mang khăn từ phòng xuống đâu ạ. Tại quầy bar hồ bơi luôn có sẵn khăn tắm khổ lớn phục vụ miễn phí cho khách bơi ạ.'),
                                                                               (1, 'Tôi bị ốm, khách sạn có bác sĩ hoặc thuốc không?', 'Dạ, khách sạn luôn có tủ thuốc y tế cơ bản (băng gạc, thuốc hạ sốt, thuốc đau bụng). Nếu quý khách mệt nặng, Lễ tân sẽ gọi Bác sĩ phòng khám đối tác đến tận phòng kiểm tra ngay lập tức ạ.'),
                                                                               (1, 'Gần khách sạn có hiệu thuốc nào không?', 'Dạ, chỉ cách khách sạn khoảng 100m có nhà thuốc Pharmacity/Long Châu mở cửa đến 23:00. Nếu quý khách cần, nhân viên bảo vệ (Bellman) có thể hỗ trợ đi mua giúp quý khách ạ.'),
                                                                               (1, 'Tôi có thể mua tour du lịch tại khách sạn không?', 'Dạ có ạ. Khách sạn có quầy Tour Desk tại sảnh hỗ trợ đặt các tour tham quan Bà Nà Hills, Hội An, Cù Lao Chàm... với giá niêm yết và hướng dẫn viên chuyên nghiệp ạ.'),
                                                                               (1, 'Khách sạn có phòng hát Karaoke không?', 'Dạ hiện tại khách sạn không có phòng Karaoke bên trong khuôn viên để đảm bảo sự yên tĩnh. Tuy nhiên, Lễ tân có thể giới thiệu và đặt chỗ giúp quý khách các quán Karaoke VIP rất gần khách sạn ạ.'),
                                                                               (1, 'Tôi chưa nhận phòng mà muốn vào đánh giá thì hệ thống báo lỗi?', 'Dạ đúng rồi ạ. Đây là tính năng bảo mật của hệ thống. Để đảm bảo 100% đánh giá là từ trải nghiệm thật, hệ thống chỉ cấp quyền đánh giá (Review) SAU KHI quý khách hoàn tất trả phòng (Check-out) thành công ạ.'),
                                                                               (1, 'Tôi có thể đính kèm ảnh chụp thực tế vào bài đánh giá phòng không?', 'Dạ hoàn toàn được ạ. Hệ thống đánh giá của chúng tôi rất hoan nghênh quý khách tải lên các hình ảnh trải nghiệm thực tế để giúp những khách hàng sau có cái nhìn trực quan nhất ạ.'),
                                                                               (1, 'Tôi không đặt phòng trên web mà đặt qua Agoda thì có đánh giá trên hệ thống này được không?', 'Dạ, nếu quý khách đặt qua các kênh bên thứ 3 (như Agoda/Booking), quý khách sẽ đánh giá trực tiếp trên app đó. Hệ thống đánh giá này chỉ dành cho khách đặt phòng trực tiếp qua Website/App của khách sạn ạ.'),
                                                                               (1, 'Ai sẽ là người đọc các đánh giá của tôi?', 'Dạ, mọi đánh giá của quý khách đều được hiển thị công khai. Đặc biệt, Giám đốc khách sạn và Trưởng các bộ phận sẽ trực tiếp đọc, phản hồi và xử lý các góp ý của quý khách ạ.'),
                                                                               (1, 'Tôi muốn khen ngợi một nhân viên lễ tân cụ thể trong bài đánh giá được không?', 'Dạ vô cùng tuyệt vời ạ! Việc quý khách nêu tên khen ngợi sẽ là động lực rất lớn cho nhân viên. Khách sạn cũng có quỹ thưởng "Nhân viên xuất sắc của tháng" dựa trên các đánh giá này ạ.'),
                                                                               (1, 'Đánh giá xong thì khi nào tôi nhận được mã giảm giá?', 'Dạ, ngay khi bài đánh giá (Review) được gửi thành công lên hệ thống, một email chứa mã giảm giá (Voucher) tự động sẽ được gửi vào hộp thư của quý khách để dùng cho lần đặt phòng sau ạ.'),
                                                                               (1, 'Có quy định gì về ngôn từ khi viết đánh giá không?', 'Dạ, hệ thống sẽ tự động lọc các đánh giá. Chúng tôi từ chối hiển thị các bài viết có ngôn từ xúc phạm, thô tục, hoặc chứa nội dung quảng cáo không liên quan đến trải nghiệm lưu trú ạ.'),
                                                                               (1, 'Tôi muốn đổi phòng lúc nhận phòng vì không thích view có được không?', 'Dạ, nếu lúc quý khách nhận phòng mà khách sạn vẫn còn phòng trống có view đẹp hơn (cùng hạng hoặc cần nâng hạng), Lễ tân sẽ rất vui lòng hỗ trợ đổi phòng cho quý khách ạ.'),
                                                                               (1, 'Nâng hạng phòng (Upgrade) lúc Check-in có bị tính phí không?', 'Dạ, nếu nâng lên hạng phòng cao cấp hơn (ví dụ từ Standard lên Deluxe), quý khách sẽ cần thanh toán khoản chênh lệch giá phòng. Thi thoảng, khách sạn cũng có chương trình Upgrade miễn phí cho khách hàng thân thiết ạ.'),
                                                                               (1, 'Trong phòng có bàn là hơi nước không?', 'Dạ, khách sạn trang bị bàn ủi khô truyền thống. Nếu quý khách cần ủi trang phục cao cấp (lụa, vest) bằng bàn là hơi nước đứng, xin vui lòng sử dụng dịch vụ Giặt ủi chuyên nghiệp của khách sạn ạ.'),
                                                                               (1, 'Gương trong phòng tắm có đèn soi mặt không?', 'Dạ có ạ. Gương phòng tắm (BATHROOM) được trang bị hệ thống đèn LED hắt sáng thông minh (LIGHTING), cực kỳ sắc nét và thuận tiện cho các chị em phụ nữ trang điểm ạ.'),
                                                                               (1, 'Có dịch vụ gọi báo thức (Wake-up call) không?', 'Dạ có ạ. Quý khách chỉ cần báo Lễ tân giờ muốn thức dậy, chúng tôi sẽ gọi điện thoại lên phòng đúng giờ để đảm bảo quý khách không lỡ chuyến bay hay lịch trình công tác ạ.'),
                                                                               (1, 'Giá phòng cuối tuần (Thứ 7, CN) có đắt hơn ngày thường không?', 'Dạ, thông thường giá phòng vào các ngày cuối tuần (Thứ 6, Thứ 7) hoặc dịp Lễ/Tết sẽ có sự điều chỉnh cao hơn một chút so với các ngày trong tuần (Từ Chủ nhật đến Thứ 5) do nhu cầu cao ạ.'),
                                                                               (1, 'Trẻ em đi bơi có cần người lớn đi kèm không?', 'Dạ có ạ. Vì lý do an toàn tuyệt đối, trẻ em dưới 12 tuổi khi sử dụng khu vực hồ bơi bắt buộc phải có phụ huynh hoặc người lớn đi kèm giám sát ạ.'),
                                                                               (1, 'Hồ bơi có khu vực nước cạn cho trẻ em không?', 'Dạ có ạ. Hồ bơi của khách sạn được thiết kế phân khu rõ ràng, có một khu vực bể vầy riêng với mực nước cạn (khoảng 0.5m) rất an toàn cho các bé vui chơi ạ.'),
                                                                               (1, 'Khách sạn có khu vui chơi trẻ em (Kids Club) không?', 'Dạ có ạ. Khách sạn có một phòng Kids Club nhỏ tại tầng 3, trang bị cầu trượt, nhà bóng và các trò chơi xếp hình để các bé giải trí trong lúc bố mẹ đi Spa hoặc Gym ạ.'),
                                                                               (1, 'Tôi làm vỡ cốc thủy tinh trong phòng có phải đền không?', 'Dạ, tùy vào mức độ và vật dụng, khách sạn sẽ có bảng giá đền bù tương ứng. Tuy nhiên với những vật dụng nhỏ như cốc thủy tinh vô tình làm vỡ, khách sạn thường sẽ linh động miễn phí cho quý khách ạ.'),
                                                                               (1, 'Khách sạn có dịch vụ đánh giày không?', 'Dạ có ạ. Trong tủ quần áo (STORAGE) có sẵn xi và bàn chải đánh giày cơ bản. Nếu quý khách cần đánh bóng chuyên nghiệp, vui lòng gọi dịch vụ buồng phòng (có tính một khoản phí nhỏ) ạ.'),
                                                                               (1, 'Nhân viên khách sạn có nói được tiếng Anh không?', 'Dạ chắc chắn rồi ạ. Đội ngũ Lễ tân, Concierge và quản lý nhà hàng của khách sạn đều giao tiếp trôi chảy bằng tiếng Anh để phục vụ khách du lịch quốc tế tốt nhất ạ.'),
                                                                               (1, 'Cửa phòng tắm là kính trong suốt hay nhám?', 'Dạ, cửa phòng tắm của các hạng phòng hiện đại thường là kính trong suốt để tạo không gian mở, nhưng luôn được trang bị hệ thống rèm kéo (Blinds) bên trong để đảm bảo sự riêng tư tuyệt đối khi cần ạ.'),
                                                                               (1, 'Tôi có được tự ý sắp xếp lại đồ đạc (kê lại giường) trong phòng không?', 'Dạ, để tránh làm trầy xước sàn gỗ và hỏng hóc tài sản, quý khách vui lòng không tự ý di chuyển giường tủ (BED, STORAGE). Nếu có nhu cầu thay đổi, hãy báo Lễ tân cử Kỹ thuật lên hỗ trợ ạ.'),
                                                                               (1, 'Tôi muốn phản ánh thái độ của nhân viên thì gặp ai?', 'Dạ, khách sạn rất xin lỗi nếu có nhân viên làm quý khách phật ý. Quý khách có thể yêu cầu gặp trực tiếp Quản lý sảnh (Duty Manager) đang trực, hoặc ghi lại phản ánh trong phần Đánh giá sau khi Check-out, Ban Giám Đốc sẽ xử lý nghiêm túc ạ.');
INSERT INTO ai_knowledge_base (admin_id, question_pattern, answer_content) VALUES
                                                                               (1, 'Khách sạn có đang có chương trình khuyến mãi nào không?', 'Dạ, khách sạn thường xuyên có các ưu đãi giảm giá Early Bird (đặt sớm) hoặc Staycation. Quý khách vui lòng kiểm tra mục "Khuyến Mãi" trên trang chủ để cập nhật các voucher giảm giá mới nhất ạ.'),
                                                                               (1, 'Tôi đặt phòng ở dài hạn (Long-stay) có được giảm giá không?', 'Dạ có ạ. Đối với khách hàng lưu trú từ 7 đêm trở lên, khách sạn luôn có chính sách giá đặc biệt (Long-stay offer) giảm từ 15-20% kèm theo ưu đãi giặt ủi. Quý khách hãy liên hệ Lễ tân để nhận báo giá chi tiết nhé.'),
                                                                               (1, 'Làm sao để trở thành khách hàng thân thiết (Membership)?', 'Dạ, ngay sau khi quý khách hoàn tất kỳ nghỉ đầu tiên và Check-out thành công, hệ thống sẽ tự động đăng ký quý khách vào hạng thẻ Thành viên tiêu chuẩn (Silver) với nhiều đặc quyền cho các lần sau ạ.'),
                                                                               (1, 'Thông tin cá nhân và thẻ tín dụng của tôi có bị lộ không?', 'Dạ quý khách hoàn toàn yên tâm. Hệ thống đặt phòng của khách sạn được mã hóa bảo mật SSL 256-bit chuẩn quốc tế. Thông tin cá nhân và dữ liệu thanh toán của quý khách được bảo mật tuyệt đối 100% ạ.'),
                                                                               (1, 'Hệ thống phòng cháy chữa cháy (PCCC) của khách sạn có an toàn không?', 'Dạ, khách sạn được trang bị hệ thống PCCC tự động tiên tiến nhất, bao gồm cảm biến khói, vòi phun nước tự động (Sprinkler) trong từng phòng và được kiểm tra bảo dưỡng định kỳ hàng tháng ạ.'),
                                                                               (1, 'Lối thoát hiểm nằm ở đâu?', 'Dạ, sơ đồ lối thoát hiểm (Evacuation Map) được dán ngay phía sau cửa chính của mỗi phòng. Lối thang bộ thoát hiểm được bố trí ở hai đầu của mỗi hành lang và có đèn báo sáng 24/24 ạ.'),
                                                                               (1, 'Trong phòng có bình chữa cháy mini không?', 'Dạ, bình chữa cháy cầm tay được bố trí sẵn tại các tủ PCCC dọc theo hành lang mỗi tầng (cách phòng quý khách chỉ vài bước chân) để đảm bảo an toàn cao nhất ạ.'),
                                                                               (1, 'Khi nghe chuông báo cháy tôi phải làm gì?', 'Dạ, quý khách vui lòng giữ bình tĩnh, tuyệt đối không sử dụng thang máy. Hãy mở cửa, đi theo biển báo dạ quang chỉ dẫn đến cầu thang bộ thoát hiểm gần nhất và di chuyển xuống tầng trệt ạ.'),
                                                                               (1, 'Tôi có được đốt nến thơm hoặc tinh dầu trong phòng không?', 'Dạ rất tiếc là không ạ. Để phòng tránh rủi ro hỏa hoạn và hệ thống báo khói vô tình kích hoạt, khách sạn quy định nghiêm cấm sử dụng các vật liệu dễ cháy, đốt nến hoặc nhang trong phòng.'),
                                                                               (1, 'Tôi mua sầu riêng và hải sản mang lên phòng ăn được không?', 'Dạ, vì sầu riêng và hải sản tươi sống có mùi rất nặng và bám lâu vào nội thất, khách sạn quy định không mang các thực phẩm này lên phòng để tránh ảnh hưởng đến những khách lưu trú sau ạ.'),
                                                                               (1, 'Tôi mang theo bếp ga mini để nấu lẩu trong phòng Standard được không?', 'Dạ tuyệt đối không ạ. Ngoại trừ hạng phòng Family có khu vực bếp từ an toàn (KITCHEN), việc sử dụng bếp ga, bếp cồn để nấu ăn trong các phòng ngủ khác là vi phạm nghiêm trọng quy định PCCC của khách sạn ạ.'),
                                                                               (1, 'Tôi có được mang loa kéo vào phòng hát hò, mở tiệc không?', 'Dạ, để đảm bảo không gian nghỉ ngơi yên tĩnh cho mọi người, khách sạn quy định không sử dụng loa công suất lớn hoặc gây ồn ào sau 22:00 đêm ạ. Mong quý khách thông cảm.'),
                                                                               (1, 'Có được mang vũ khí, vật liệu nổ vào khách sạn không?', 'Dạ đây là quy định cấm tuyệt đối theo pháp luật Việt Nam. Khách sạn nghiêm cấm mang theo vũ khí, chất độc hại, chất nổ và các loại chất cấm (ma túy) vào khuôn viên khách sạn ạ.'),
                                                                               (1, 'Tôi đánh mất thẻ xe ở tầng hầm thì phải làm sao?', 'Dạ, quý khách vui lòng liên hệ ngay với Lễ tân hoặc Bảo vệ bãi xe, cung cấp giấy tờ tùy thân và giấy tờ xe để chúng tôi xác minh và hỗ trợ quý khách lấy xe ra an toàn ạ (có thu phụ phí làm lại thẻ).'),
                                                                               (1, 'Khách sạn có dịch vụ gửi xe qua đêm cho bạn tôi không lưu trú không?', 'Dạ, bãi đỗ xe của khách sạn ưu tiên phục vụ khách lưu trú. Đối với khách ngoài (không đặt phòng), khách sạn sẽ thu phí gửi xe qua đêm theo bảng giá niêm yết tại hầm xe ạ.'),
                                                                               (1, 'Khách sạn có xe điện (Buggy) chở ra bãi biển không?', 'Dạ có ạ. Khách sạn có cung cấp dịch vụ xe Buggy đưa đón khách ra bãi biển hoàn toàn miễn phí. Các chuyến khởi hành liên tục mỗi 15 phút tại sảnh chính ạ.'),
                                                                               (1, 'Tôi muốn tổ chức tiệc nướng BBQ ngoài trời có được không?', 'Dạ tuyệt vời ạ! Khách sạn có khu vực BBQ cạnh hồ bơi. Quý khách vui lòng đặt trước với nhà hàng để chúng tôi chuẩn bị bếp nướng, nguyên liệu và nhân viên phục vụ riêng cho quý khách nhé.'),
                                                                               (1, 'Tôi muốn mỗi ngày đều có hoa tươi thay mới trong phòng?', 'Dạ, khách sạn sẵn sàng hỗ trợ yêu cầu này (có tính phí dịch vụ). Quý khách hãy báo cho Lễ tân loại hoa yêu thích để bộ phận Buồng phòng setup mỗi sáng nhé.'),
                                                                               (1, 'Khách sạn có bữa sáng nổi trên hồ bơi (Floating Breakfast) không?', 'Dạ có ạ. Đây là dịch vụ cực kỳ được yêu thích để chụp hình sống ảo. Quý khách vui lòng đặt trước 1 ngày để nhân viên chuẩn bị khay nổi và phục vụ tận hồ bơi cho quý khách ạ.'),
                                                                               (1, 'Tôi có thể đưa ekip chụp hình cưới/quay phim vào khuôn viên khách sạn không?', 'Dạ, khách sạn rất hân hạnh được làm bối cảnh cho những khoảnh khắc đẹp của quý khách. Tuy nhiên, việc chụp ảnh thương mại/ảnh cưới cần liên hệ trước với bộ phận Marketing để đăng ký và đóng phí địa điểm ạ.'),
                                                                               (1, 'Khách sạn có bay Flycam (Drone) được không?', 'Dạ, vì lý do an toàn bay và bảo vệ sự riêng tư cho các khách lưu trú khác tại hồ bơi/ban công, khách sạn hiện không cho phép sử dụng Flycam trong khu vực khuôn viên ạ.'),
                                                                               (1, 'Tôi có tài xế riêng, khách sạn có phòng ngủ cho tài xế không?', 'Dạ có ạ. Khách sạn có bố trí khu vực phòng nghỉ cơ bản dành riêng cho nội bộ và tài xế của khách hàng. Quý khách vui lòng đăng ký trước với Lễ tân để chúng tôi sắp xếp chỗ ngả lưng cho bác tài ạ.'),
                                                                               (1, 'Tôi quên mật khẩu két sắt (Safe box) trong phòng rồi!', 'Dạ quý khách đừng lo. Vui lòng gọi ngay số 0, Quản lý sảnh và bộ phận An ninh sẽ cùng lên phòng, tiến hành xác minh danh tính và sử dụng chìa khóa Master để mở két sắt trước sự chứng kiến của quý khách ạ.'),
                                                                               (1, 'AI có biết tôi là ai không?', 'Dạ, tôi là trợ lý ảo được lập trình để hỗ trợ quý khách trên hệ thống đặt phòng. Thông qua tài khoản đăng nhập của quý khách, tôi biết quý khách là một vị khách hàng vô cùng quan trọng của khách sạn chúng tôi ạ!'),
                                                                               (1, 'Trợ lý ảo có buồn ngủ không? Nghỉ ngơi chưa?', 'Dạ không ạ! Tôi là AI nên lúc nào năng lượng cũng tràn trề 100%. Tôi túc trực ở đây 24/7, bất kể ngày đêm, Chủ Nhật hay Lễ Tết để luôn sẵn sàng hỗ trợ quý khách ngay lập tức ạ.'),
                                                                               (1, 'Bạn có thể tự ý giảm giá phòng cho tôi 50% không?', 'Dạ, tôi rất muốn tặng quý khách một mức giá thật tốt, nhưng tôi chỉ là AI hỗ trợ thông tin và không có quyền can thiệp vào bảng giá niêm yết của Ban Giám Đốc ạ. Quý khách hãy săn các mã voucher trên trang chủ nhé!'),
                                                                               (1, 'Tôi muốn nói chuyện với con người thật, không chat với Bot nữa!', 'Dạ, tôi rất xin lỗi nếu chưa giải đáp được trọn vẹn vấn đề của quý khách. Quý khách vui lòng liên hệ trực tiếp số Hotline 0236.XXX.XXXX để gặp ngay chuyên viên Lễ tân hỗ trợ lập tức ạ.'),
                                                                               (1, 'Chatbot trả lời giỏi quá, tôi cho bạn tiền Tip được không?', 'Dạ, lời khen của quý khách chính là phần tiền Tip giá trị nhất đối với tôi rồi ạ! Tôi rất vui vì đã giúp ích được cho quý khách. Chúc quý khách một kỳ nghỉ thật tuyệt vời!'),
                                                                               (1, 'Tại sao bắt tôi phải cọc tiền? Khách sạn khác có bắt cọc đâu!', 'Dạ, khách sạn rất hiểu sự e ngại của quý khách. Tuy nhiên, việc cọc 20% là quy trình bắt buộc để hệ thống khóa phòng trống trên toàn bộ nền tảng, đảm bảo 100% khi quý khách đến nơi sẽ có phòng đẹp và phục vụ chu đáo nhất ạ.'),
                                                                               (1, 'Nếu không cho tôi check in sớm, tôi sẽ đánh giá 1 sao!', 'Dạ, khách sạn vô cùng thấu hiểu sự mệt mỏi của quý khách sau chuyến đi dài. Chúng tôi luôn ưu tiên cho khách nhận phòng sớm nhất có thể nếu có phòng trống. Rất mong quý khách thông cảm cho quy trình vệ sinh phòng chuẩn 5 sao cần nhiều thời gian ạ.'),
                                                                               (1, 'Web bị lỗi, tôi chuyển khoản trừ tiền rồi mà chưa có email xác nhận?', 'Dạ, quý khách cứ yên tâm ạ! Nếu ngân hàng đã báo trừ tiền, quý khách vui lòng chụp lại biên lai giao dịch và gửi cho Lễ tân qua Fanpage/Hotline. Kế toán sẽ đối soát và xác nhận phòng cho quý khách ngay lập tức ạ.'),
                                                                               (1, 'Tổng đài khách sạn gọi mãi không ai nghe máy?', 'Dạ, thành thật xin lỗi quý khách nếu đường dây nóng đang bị quá tải do nhiều khách hàng cùng liên hệ. Quý khách có thể để lại số điện thoại tại đây, tôi sẽ chuyển ngay cho Lễ tân gọi lại trong ít phút nữa ạ.'),
                                                                               (1, 'Khách sạn của bạn có tốt hơn khách sạn Mường Thanh/Vinpearl bên cạnh không?', 'Dạ, mỗi khách sạn đều có phong cách và điểm mạnh riêng. Khách sạn chúng tôi tự hào mang đến trải nghiệm lưu trú hiện đại, dịch vụ cá nhân hóa tận tâm và hệ sinh thái tiện ích chuẩn 5 sao để làm hài lòng mọi khách hàng ạ.'),
                                                                               (1, 'Gối của khách sạn êm quá, tôi mua mang về được không?', 'Dạ được ạ! Rất nhiều khách hàng đã phải lòng bộ chăn ga gối nệm (BED) của khách sạn. Chúng tôi có bán lẻ các sản phẩm gối lông vũ cao cấp chuẩn khách sạn tại quầy lưu niệm ở sảnh ạ.'),
                                                                               (1, 'Đánh giá (Review) có được tải kèm Video không?', 'Dạ, hiện tại để tối ưu tốc độ hệ thống, chức năng đánh giá sau khi Check-out chỉ hỗ trợ tải lên Hình ảnh thực tế cùng với nội dung văn bản. Rất mong quý khách chia sẻ những bức ảnh đẹp nhất nhé ạ.'),
                                                                               (1, 'Tôi đánh giá 5 sao thì có được hoàn lại tiền cọc 20% không?', 'Dạ, tiền cọc 20% là để trừ thẳng vào tổng chi phí tiền phòng của quý khách lúc thanh toán Check-out rồi ạ. Khi quý khách đánh giá 5 sao, hệ thống sẽ tự động tặng mã giảm giá (Voucher) cho lần đặt phòng tiếp theo ạ.'),
                                                                               (1, 'Chúc khách sạn làm ăn phát đạt', 'Dạ, thay mặt toàn bộ đội ngũ nhân viên và Ban Giám Đốc khách sạn, tôi xin chân thành cảm ơn lời chúc tốt đẹp của quý khách. Rất mong được sớm đón tiếp quý khách đến nghỉ dưỡng ạ!'),
                                                                               (1, 'Tôi có thể hút xì gà (Cigar) ở đâu?', 'Dạ, cũng giống như thuốc lá, quý khách không được hút xì gà trong phòng kín. Khách sạn có khu vực Cigar Lounge riêng biệt tại quầy Bar với hệ thống hút mùi chuyên nghiệp dành riêng cho quý khách ạ.'),
                                                                               (1, 'Khách sạn có dịch vụ đưa đón bằng xe Limousine không?', 'Dạ có ạ. Để nâng tầm trải nghiệm, khách sạn cung cấp dịch vụ đưa đón bằng xe Limousine Dcar 9 chỗ siêu sang. Quý khách vui lòng đặt trước với bộ phận Concierge để có giá tốt nhất ạ.'),
                                                                               (1, 'Thẻ căn cước công dân (CCCD) trên app VNeID có dùng để check in được không?', 'Dạ hoàn toàn hợp lệ ạ. Quý khách chỉ cần mở ứng dụng VNeID (mức độ 2), nhân viên Lễ tân sẽ đối chiếu thông tin để làm thủ tục nhận phòng cho quý khách một cách nhanh chóng và thuận tiện.');